-- Create a demo_profiles table for display purposes (not linked to auth)
CREATE TABLE IF NOT EXISTS public.demo_profiles (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  full_name TEXT NOT NULL,
  full_name_bn TEXT,
  email TEXT,
  phone TEXT,
  avatar_url TEXT,
  district_id UUID REFERENCES public.districts(id),
  created_at TIMESTAMP WITH TIME ZONE DEFAULT now()
);

-- Enable RLS and allow public read
ALTER TABLE public.demo_profiles ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Demo profiles are viewable" ON public.demo_profiles FOR SELECT USING (true);

